import{_ as n,c as a,o as s,ag as t}from"./chunks/framework.QPV3Ar9-.js";const o="/assets/agent0.CfOi1y0_.png",i="/assets/agent1.B3mvgfB2.png",r="/assets/agent2.DH-1h9GP.png",p="/assets/agent3.CBfCJ_DV.png",l="/assets/agent4.BEG_w41m.png",c="/assets/agent7.BQIWOUed.jpeg",d="/assets/agent5.K3I0SIuf.png",m="/assets/agent6.Hj3aLwzs.png",u="/assets/gpu1.BqYtvfhm.jpeg",h="/assets/gpu2.Ctk8v8IU.jpeg",g="/assets/gpu3.DsMLQ_4f.jpg",I=JSON.parse('{"title":"Custom","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en/guide/oneclickvirt/oneclickvirt_custom.md","filePath":"en/guide/oneclickvirt/oneclickvirt_custom.md","lastUpdated":1778992413000}'),f={name:"en/guide/oneclickvirt/oneclickvirt_custom.md"};function b(y,e,v,_,k,w){return s(),a("div",null,e[0]||(e[0]=[t('<h1 id="custom" tabindex="-1">Custom <a class="header-anchor" href="#custom" aria-label="Permalink to &quot;Custom&quot;">​</a></h1><h2 id="manage-nodes-without-a-dedicated-public-ipv4-address-via-agent-mode" tabindex="-1">Manage nodes without a dedicated public IPv4 address via Agent mode <a class="header-anchor" href="#manage-nodes-without-a-dedicated-public-ipv4-address-via-agent-mode" aria-label="Permalink to &quot;Manage nodes without a dedicated public IPv4 address via Agent mode&quot;">​</a></h2><p>For some local devices, the node may have IPv4 internet access but does not have a fixed/dynamic dedicated public IPv4 address. In this case, you cannot directly manage the node through SSH in standard mode. Here we provide a new management method: Agent mode.</p><p><img src="'+o+'" alt="" loading="lazy"></p><p>When adding a new node, click the corresponding mode, then enter the Basic Information page.</p><p><img src="'+i+'" alt="" loading="lazy"></p><p>Unlike standard mode, IP address and port are no longer required fields. You can still manage the node if they are left empty. For local nodes, do not fill these two fields. For cloud servers or other nodes with a fixed public IPv4 address, you can fill them in. If they are left empty, only the <code>Network Type</code> option <code>No Port Mapping</code> is supported later. If filled in, the <code>Network Type</code> options are the same as standard mode.</p><p><img src="'+r+'" alt="" loading="lazy"></p><p>After clicking Save, you can see the command generation button in <code>Connection Configuration</code>. Once saved, the node token is fixed. If you need to update the token, you must delete and re-add the node, and all configuration must be filled again. So do not leak the token.</p><p><img src="'+p+'" alt="" loading="lazy"></p><p>After clicking Generate (as shown below), copy the command and run it directly on the local node server to complete management access. After installation finishes, use the detection button at the bottom of this page for verification.</p><p><img src="'+l+'" alt="" loading="lazy"></p><p><img src="'+c+'" alt="" loading="lazy"></p><p>After detection succeeds, the following configuration pages can be operated according to the original standard-mode instructions; there is no major difference.</p><p><img src="'+d+'" alt="" loading="lazy"></p><p>Only this section differs for local nodes: choose <code>No Port Mapping</code>, so you can later manually perform <code>Manual Add Port</code> from the administrator <code>Port Management</code> page, and tunnel ports to the controller&#39;s IPv4 address for use.</p><p><img src="'+m+`" alt="" loading="lazy"></p><p>When manually adding port mapping, choose <code>Controller Forwarding (Intranet Penetration)</code>. Non-required fields can be left empty. The system will automatically select controller ports for mapping.</p><p>There is one limitation: make sure the <code>Controller Panel</code> is deployed by <code>Script Deployment</code> or local compiled deployment. Docker or Docker Compose deployment is not supported. Non-<code>Linux</code> deployment is also not supported, because the controller deployment must have firewall control over the server where it is deployed, so deployment in a <code>root environment</code> is required.</p><p>The <code>Intranet Penetration Port</code> feature is <code>only for nodes managed in Agent mode</code>, forwarding via WSS proxy. During deployment, make sure your reverse proxy is configured for WS/WSS according to the instructions. Do not forget this when configuring your own reverse proxy.</p><p>Also, if the controller is upgraded, make sure to upgrade the node side accordingly. Click Edit Node, go to <code>Connection Configuration</code>, regenerate the command, and run the installation again.</p><h2 id="use-lxd-incus-to-create-containers-with-shared-gpu-devices" tabindex="-1">Use LXD/INCUS to create containers with shared GPU devices <a class="header-anchor" href="#use-lxd-incus-to-create-containers-with-shared-gpu-devices" aria-label="Permalink to &quot;Use LXD/INCUS to create containers with shared GPU devices&quot;">​</a></h2><p>For nodes that need shared GPU devices, make sure the node has already installed the corresponding GPU driver before management, and that GPU commands run correctly, for example:</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvidia-smi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Make sure the output is similar to:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>root@a12-ThinkStation-P620:/root/sharefile# nvidia-smi</span></span>
<span class="line"><span>Sat May 16 20:23:07 2026       </span></span>
<span class="line"><span>+---------------------------------------------------------------------------------------+</span></span>
<span class="line"><span>| NVIDIA-SMI 535.171.04             Driver Version: 535.171.04   CUDA Version: 12.2     |</span></span>
<span class="line"><span>|-----------------------------------------+----------------------+----------------------|</span></span>
<span class="line"><span>| GPU  Name                 Persistence-M | Bus-Id        Disp.A | Volatile Uncorr. ECC |</span></span>
<span class="line"><span>| Fan  Temp   Perf          Pwr:Usage/Cap |         Memory-Usage | GPU-Util  Compute M. |</span></span>
<span class="line"><span>|                                         |                      |               MIG M. |</span></span>
<span class="line"><span>|=========================================+======================+======================|</span></span>
<span class="line"><span>|   0  NVIDIA RTX A6000               Off | 00000000:61:00.0 Off |                  Off |</span></span>
<span class="line"><span>| 30%   42C    P0              83W / 300W |      0MiB / 49140MiB |      1%      Default |</span></span>
<span class="line"><span>|                                         |                      |                  N/A |</span></span>
<span class="line"><span>+-----------------------------------------+----------------------+----------------------+</span></span>
<span class="line"><span>                                                                                         </span></span>
<span class="line"><span>+---------------------------------------------------------------------------------------+</span></span>
<span class="line"><span>| Processes:                                                                            |</span></span>
<span class="line"><span>|  GPU   GI   CI        PID   Type   Process name                            GPU Memory |</span></span>
<span class="line"><span>|        ID   ID                                                             Usage      |</span></span>
<span class="line"><span>|=======================================================================================|</span></span>
<span class="line"><span>|  No running processes found                                                           |</span></span>
<span class="line"><span>+---------------------------------------------------------------------------------------+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><p>Only after the host machine has the driver installed can GPU resources be shared into containers.</p><p>Then follow the Incus/LXD tutorial in this documentation to complete local environment installation. After installation, finish Agent-mode management through the controller and pass health checks before proceeding.</p><p>It is recommended to enable node &quot;redemption-code-only claim&quot; mode, then create containers with GPU devices from the administrator redemption-code page.</p><p><img src="`+u+'" alt="" loading="lazy"></p><p>After creation succeeds, switch to the administrator&#39;s regular-user view to redeem it, then switch back to administrator view and go to the Port Management page to tunnel container ports so you can connect and configure directly via web SSH.</p><p><img src="'+h+'" alt="" loading="lazy"></p><p>After adding successfully, you can directly use web SSH to connect and manage this new local container.</p><p>Inside the container, install the same driver version as the external host. During installation, make sure it does not load into the kernel by adding the <code>--no-kernel-module</code> parameter.</p><p>For detailed driver installation steps, refer to: <a href="https://www.spiritysdx.top/20240513/#%E5%AE%B9%E5%99%A8%E5%86%85%E5%AE%89%E8%A3%85gpu%E9%A9%B1%E5%8A%A8" target="_blank" rel="noreferrer">https://www.spiritysdx.top/20240513/#容器内安装gpu驱动</a></p><p>After installation, running <code>nvidia-smi</code> inside the container should also return output, which proves GPU sharing is active.</p><p><img src="'+g+'" alt="" loading="lazy"></p><p>At this point, you can stop this container and use it as a template. Use the redemption-code batch container creation &quot;copy mode&quot;, set this container as the source container, and clone new containers from it.</p>',38)]))}const A=n(f,[["render",b]]);export{I as __pageData,A as default};
